function waitForMessage(socket: {
  once: (
    event: "error" | "message",
    listener: (value: Error | { toString(): string }) => void
  ) => void;
}) {
  return new Promise<string>((resolve, reject) => {
    socket.once("error", (error) => {
      reject(error);
    });
    socket.once("message", (data) => {
      resolve(data.toString());
    });
  });
}

